// 处理 AI 导师的回复并添加元数据
const agentResponse = $input.first().json;
const chatInput = $('Chat Trigger').first().json;

// 分析回复类型
const responseAnalysis = analyzeResponse(agentResponse.output);

// 构建响应
return {
  json: {
    message: agentResponse.output,
    metadata: {
      timestamp: new Date().toISOString(),
      conversationId: chatInput.conversationId || generateId(),
      userId: chatInput.userId || 'anonymous',
      responseTime: Date.now() - new Date(chatInput.timestamp).getTime(),
      analysis: responseAnalysis
    },
    suggestions: generateFollowUpQuestions(responseAnalysis.topic),
    resources: recommendResources(responseAnalysis.topic)
  }
};

function analyzeResponse(response) {
  const topics = ['概念解释', '代码示例', '学习建议', '进度查询', '数学计算', '资源推荐'];
  const responseLower = response.toLowerCase();

  const detectedTopics = topics.filter(topic => {
    const keywords = {
      '概念解释': ['什么是', '概念', '原理', '解释', '理解'],
      '代码示例': ['代码', '示例', '实现', 'python', 'function'],
      '学习建议': ['建议', '如何学', '路线', '方法', '技巧'],
      '进度查询': ['进度', '完成', '还有多少', '下一步'],
      '数学计算': ['计算', '等于', '结果', '数值'],
      '资源推荐': ['推荐', '资源', '教程', '课程', '书籍']
    };
    return keywords[topic]?.some(k => responseLower.includes(k));
  });

  return {
    topics: detectedTopics,
    mainTopic: detectedTopics[0] || '一般对话',
    sentiment: 'neutral',
    complexity: response.length > 500 ? 'high' : 'medium'
  };
}

function generateFollowUpQuestions(topic) {
  const questions = {
    '概念解释': ['能举个具体的例子吗？', '这个概念在实际中怎么应用？', '它和其他概念有什么区别？'],
    '代码示例': ['这段代码的时间复杂度是多少？', '有没有更优化的写法？', '如何处理边界情况？'],
    '学习建议': ['我应该先学什么？', '每天需要花多少时间？', '有什么好的练习方法？'],
    '进度查询': ['我现在的进度如何？', '接下来应该学什么？', '预计多久能完成？'],
    '数学计算': ['这个公式是怎么推导的？', '有没有更简单的计算方法？', '这个结果意味着什么？'],
    '资源推荐': ['这个资源适合什么水平？', '还有其他类似的资源吗？', '这些资源的学习顺序是怎样的？']
  };

  return (questions[topic] || questions['概念解释']).slice(0, 3);
}

