function generateId() {
  return 'conv_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
}

// 记录对话日志用于分析
const conversationData = {
  userId: $input.first().json.metadata.userId,
  conversationId: $input.first().json.metadata.conversationId,
  timestamp: new Date().toISOString(),
  userMessage: $('Chat Trigger').first().json.message,
  botResponse: $input.first().json.message,
  topics: $input.first().json.metadata.analysis.topics,
